INSERT
  INTO
       DELI_MEMBER
       (
       MEMBER_NO
     , MEMBER_ID
     , MEMBER_PW
     , MEMBER_NAME
     , ADDRESS
       )
VALUES 
       (
       SEQ_MEMBER_NO.NEXTVAL
     , #{memberId}
     , #{memberPw}
     , #{memberName}
     , #{address}
       )

INSERT
  INTO
       REVIEW
       (
       REVIEW_NO
     , ORDER_NO
     , MEMBER_NO
     , REVIEW_STAR
       )
VALUES
       (
       SEQ_REVIEW_NO.NEXTVAL
     , #{orderNo}  
     , #{memberNo}
     , #{reviewStar} 
       )
